#!/bin/bash

# Check if a configuration file name is provided
if [ -z "$1" ]; then
  echo "Usage: $0 <config_file>"
  exit 1
fi

CONFIG_FILE=$1

# Check if the config file exists in /etc/configs/
if [ ! -f "/etc/configs/$CONFIG_FILE" ]; then
  echo "Error: Configuration file '$CONFIG_FILE' not found in /etc/configs/"
  exit 1
fi

# Display the contents of the configuration file
cat "/etc/configs/$CONFIG_FILE"